/* =========================================================
   顶栏高度 & 内部元素整体上下移动
   ========================================================= */

:root {
    --chat-header-height: 100px; 
}

.header-btn-back,
.header-profile-section,
.header-btn-phone,
.header-btn-video,
.header-btn-info {
    margin-top: 20px !important; 
}

/* =========================================================
   顶栏背景色
   ========================================================= */
:root {
    --chat-header-bg: #F2F2F2;
    --chat-header-border: transparent;
    --chat-header-blur: 0px; 
}

/* =========================================================
   头像呼吸灯动画
   ========================================================= */
@keyframes avatarGrayBreathe {
    0% {
        box-shadow: 0 0 4px rgba(150, 150, 150, 0.3), 0 0 0px 0px rgba(150, 150, 150, 0.2);
    }
    50% {
        box-shadow: 0 0 12px rgba(150, 150, 150, 0.6), 0 0 0px 4px rgba(150, 150, 150, 0.15);
    }
    100% {
        box-shadow: 0 0 4px rgba(150, 150, 150, 0.3), 0 0 0px 0px rgba(150, 150, 150, 0.2);
    }
}

/* 返回按钮 */
.chat-detail-screen .header-btn-back {
    background: transparent !important; 
    color: #A0A0A0 !important;
    box-shadow: none !important;
    border: none !important;
    width: auto !important;
    padding-right: 8px !important;
    display: flex !important;
    align-items: center !important;
}

.chat-detail-screen .header-btn-back::after {
    content: "Back" !important;
    color: #A0A0A0 !important;
    font-size: 16px !important;
    margin-left: 4px !important;
    font-weight: 400 !important;
    line-height: 1 !important;
}

/* 隐藏顶栏原生头像 */
.header-avatar-container {
    display: none !important;
}

/* 昵称区域居中 */
.header-profile-section {
    position: absolute !important;
    left: 50% !important;
    transform: translate(-50%, 4px) !important; 
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    justify-content: center !important;
    pointer-events: none !important; 
}

/* 名字样式 */
.chat-detail-screen .chat-header-title {
    background: transparent !important;
    color: #262626 !important;
    padding: 0 !important;
    font-size: 16px !important;
    font-weight: 600 !important;
}

/* 隐藏原生副标题 */
.chat-detail-screen .chat-header-subtitle {
    display: none !important; 
}

/* 在线状态伪元素 */
.header-profile-section::after {
    content: "온라인.." !important;
    font-size: 11px !important;
    color: #A0A0A0 !important;
    font-weight: 400 !important;
    margin-top: -3px !important;
    line-height: 1.2 !important;
}

/* 隐藏音视频按钮（保留点击） */
.header-btn-phone, 
.header-btn-video {
    opacity: 0 !important; 
    pointer-events: auto !important;
}

/* 隐藏设置按钮原生图标 */
.header-btn-info svg {
    display: none !important; 
}

/* 设置按钮换成角色头像+呼吸灯 */
.header-btn-info {
    background-image: var(--char-avatar) !important;
    background-size: cover !important;
    background-position: center !important;
    background-color: #E0E0E0 !important;
    width: 34px !important;  
    height: 34px !important;
    border-radius: 50% !important;
    border: 1px solid rgba(200, 200, 200, 0.3) !important;
    padding: 0 !important;
    margin-left: 8px !important; 
    pointer-events: auto !important;
    animation: avatarGrayBreathe 3s infinite ease-in-out !important;
}

/* =========================================================
   底部栏全局调整
   ========================================================= */
:root {
    --input-area-border-top: none;
    --input-area-padding: 8px 12px;
    --input-area-min-height: auto; 
}

/* 胶囊框 */
.input-action-bar-custom {
    border: 1px solid #D1D1D1 !important;
    border-radius: 18px !important;
    background: #ffffff !important;
    min-height: 32px !important;
    padding: 0 4px 0 0 !important;
    margin-left: 8px !important;
    margin-right: 42px !important;
    position: relative !important;
    overflow: visible !important;
    transition: border-color 0.3s ease, box-shadow 0.3s ease !important;
}

/* 输入框本体 */
.input-box-custom {
    border: none !important;
    background: transparent !important;
    padding: 6px 14px !important;
    min-height: 32px !important;
}

/* 右侧按钮组 */
.input-btns-right {
    position: static !important;
    align-items: center !important;
    gap: 4px !important;
}

/* 加号按钮 */
.input-btn-plus svg { display: none !important; }
.input-btn-plus {
    background-image: url("https://img.heliar.top/file/1777265932829_retouch_2026042712583476.png") !important;
    background-repeat: no-repeat !important;
    background-size: 24px 24px !important;
    background-position: center !important;
    transform: translate(0px, -5px) !important;
    width: 28px !important;
    height: 28px !important;
}

/* 表情按钮 */
.input-btn-sticker svg { display: none !important; }
.input-btn-sticker {
    background-image: url("https://img.heliar.top/file/1777265562019_retouch_2026042712495900.png") !important;
    background-repeat: no-repeat !important;
    background-size: 22px 22px !important;
    background-position: center !important;
    transform: translate(0px, 0px) !important;
    width: 24px !important;
    height: 24px !important;
    margin-right: 4px !important;
}

/* 语音按钮（隐藏但保留占位） */
.input-btn-mic {
    opacity: 0 !important;
    width: 22px !important;
    pointer-events: auto !important;
    margin: 0 !important;
}

/* AI 发送按钮（移出框外） */
.input-btn-ai svg { display: none !important; }
.input-btn-ai {
    position: absolute !important;
    top: 50% !important;
    transform: translateY(-50%) !important;
    background-image: url("https://img.heliar.top/file/1777265557400_retouch_2026042712502036.png") !important;
    background-repeat: no-repeat !important;
    right: -40px !important;
    margin-top: 0px !important;
    background-size: 25px 25px !important;
    background-position: center !important;
    width: 28px !important;
    height: 28px !important;
}

/* 隐藏原生占位符 */
.input-box-custom::placeholder {
    color: transparent !important;
    -webkit-text-fill-color: transparent !important;
    opacity: 0 !important;
}

/* 自定义占位符 */
.input-action-bar-custom:has(.input-box-custom:placeholder-shown)::before {
    content: 'Message' !important;
    position: absolute !important;
    left: 18px !important;
    top: 50% !important;
    transform: translateY(-50%) !important;
    color: #8e8e8e !important;
    font-size: 14px !important;
    pointer-events: none !important;
    white-space: nowrap !important;
    z-index: 5 !important;
}

.input-action-bar-custom:focus-within::before {
    display: none !important;
}

/* 输入框聚焦光晕 */
.input-action-bar-custom:focus-within {
    border-color: #A0A0A0 !important; 
    box-shadow: 0 0 0 3px rgba(160, 160, 160, 0.1) !important;
}

/* 按钮过渡动画 */
.input-btn-plus, 
.input-btn-sticker, 
.input-btn-ai, 
.header-btn-back, 
.header-btn-info {
    transition: transform 0.2s cubic-bezier(0.25, 1, 0.5, 1), opacity 0.2s ease !important;
}

/* 按压反馈 */
.header-btn-back:active, 
.header-btn-info:active,
.input-btn-sticker:active {
    transform: scale(0.85) !important;
    opacity: 0.6 !important;
}

.input-btn-plus:active {
    transform: translate(0px, -5px) scale(0.85) !important;
    opacity: 0.6 !important;
}

.input-btn-ai:active {
    transform: translateY(-50%) scale(0.85) !important;
    opacity: 0.6 !important;
}

/* =========================================================
   气泡样式（来自朦胧诗）
   ========================================================= */
:root {
  /* 我方气泡 */
  --bubble-me-bg: #dbe6f2; 
  --bubble-me-color: #5c636a;
  --bubble-me-font-size: 14px;      
  --bubble-me-padding: 8px 14px;    
  --bubble-me-radius: 18px;
  --bubble-me-radius-first: 18px 18px 4px 18px;
  --bubble-me-radius-mid: 18px 4px 4px 18px;
  --bubble-me-radius-last: 18px 4px 18px 18px;
  --bubble-me-shadow: 
    inset 0px 3px 6px -1px rgba(140, 165, 190, 0.45),  
    inset 0px -3px 6px -1px rgba(140, 165, 190, 0.45); 
  --bubble-me-border: none; 

  /* 对方气泡 */
  --bubble-them-bg: #ffffff; 
  --bubble-them-color: #5c636a;
  --bubble-them-font-size: 14px;      
  --bubble-them-padding: 8px 14px;    
  --bubble-them-radius: 18px;
  --bubble-them-radius-first: 18px 18px 18px 4px;
  --bubble-them-radius-mid: 4px 18px 18px 4px;
  --bubble-them-radius-last: 4px 18px 18px 18px;
  --bubble-them-shadow: 
    inset 0px 3px 6px -1px rgba(140, 155, 170, 0.18),  
    inset 0px -3px 6px -1px rgba(140, 155, 170, 0.18); 
  --bubble-them-border: none; 
}

/* 隐藏 WhatsApp 样式时间 */
.msg-me .msg-wa-meta,
.msg-them .msg-wa-meta {
  display: none !important;
}

/* 头像：连续消息只显最后一条 */
.msg-avatar-them-container,
.msg-avatar-me-container {
  visibility: hidden !important; 
}
.msg-avatar-them-container.is-last,
.msg-avatar-them-container.is-single,
.msg-avatar-me-container.is-last,
.msg-avatar-me-container.is-single {
  visibility: visible !important;
}

:root {
  --avatar-margin: 8px;
  --plain-avatar-gap: 8px;
}

/* 解除气泡溢出裁剪 */
.msg-me, .msg-them,
.bubble-deco-me, .bubble-deco-them,
.bubble-me-custom, .bubble-them-custom,
.msg-plain-me, .msg-plain-them {
  overflow: visible !important;
}

.bubble-deco-me, .bubble-deco-them {
  position: relative !important;
}

/* 我方气泡尾贴图（右下角） */
.msg-me.is-last .bubble-deco-me::after,
.msg-me.is-single .bubble-deco-me::after {
  content: "";
  display: block !important;
  position: absolute;
  background: url("https://img.heliar.top/file/1780391320764_retouch_2026060216563422.png") no-repeat center/contain;
  pointer-events: none;
  z-index: 100 !important;
  width: 15px;
  height: 15px;
  bottom: -1px;
  right: -3px;
}

/* 对方气泡尾贴图（左下角） */
.msg-them.is-last .bubble-deco-them::after,
.msg-them.is-single .bubble-deco-them::after {
  content: "";
  display: block !important;
  position: absolute;
  background: url("https://img.heliar.top/file/1780391322281_retouch_2026060217052033.png") no-repeat center/contain;
  pointer-events: none;
  z-index: 100 !important;
  width: 15px;
  height: 15px;
  bottom: 0px;
  left: -4px;
}

/* 消息间距 */
.msg-bubble-wrapper {
  margin-top: 0px !important;
}
.msg-bubble-wrapper.is-first,
.msg-bubble-wrapper.is-mid {
  margin-bottom: 4px !important;
}
.msg-bubble-wrapper.is-last,
.msg-bubble-wrapper.is-single {
  margin-bottom: 20px !important; 
}
:root {
  --plain-gap-within-group: 4px !important; 
  --plain-gap-between-groups: 20px !important;
}

/* 头像对齐位置 */
.msg-avatar-them-container,
.msg-avatar-me-container {
  margin-top: 0px !important; 
  transform: translateY(15px) !important; 
}

/* 旁白 */
:root {
  --narration-color: #4a5b6d !important;
  --narration-weight: 500 !important;
}
@keyframes narrationPulse {
  0% { transform: scale(1); }
  50% { transform: scale(1.02); }
  100% { transform: scale(1); }
}
.msg-narration-custom {
  animation: narrationPulse 4s ease-in-out infinite !important;
  display: inline-block !important;
}

/* 头像双层环 */
.msg-avatar-them-container,
.msg-avatar-me-container,
.msg-avatar-them-inner,
.msg-avatar-me-inner {
  overflow: visible !important;
  background: transparent !important;
}
.msg-avatar-them-inner img,
.msg-avatar-me-inner img,
.msg-avatar-custom {
  border-radius: 50% !important; 
  box-sizing: border-box !important;
  object-fit: cover !important;
  border: 2px solid #ffffff !important;
  box-shadow: 0 0 0 2px #dbe6f2 !important; 
}
:root {
  --plain-avatar-gap: 12px;
}

/* 时间戳 */
:root {
  --timestamp-color: #4a5b6d !important; 
  --timestamp-size: 10px !important;
  --timestamp-weight: 500 !important;
}
.timestamp-custom {
  background-color: #f0f2f5 !important;
  color: #4a5b6d !important; 
  border-radius: 3px !important;
  padding: 2px 8px !important;
  box-shadow: 1.5px 1.5px 0px 0px #d8dde4 !important;
  border: 1px solid #e2e6ea !important;
  display: block !important;
  width: fit-content !important; 
  margin-left: auto !important;  
  margin-right: auto !important; 
  align-self: center !important; 
  text-align: center !important;
  margin-top: 10px !important;
  margin-bottom: 12px !important;
}

/* 头像头饰贴图 */
.msg-avatar-me-container,
.msg-avatar-them-container {
  position: relative !important;
  overflow: visible !important;
}
.msg-avatar-me-container::after {
  content: "" !important;
