  background-position: center !important;
  pointer-events: none !important;
  z-index: 100 !important;
  width: 28px !important;
  height: 28px !important;
  top: -29px !important;
  left: 14px !important;
}

/* 头饰悬浮动画 */
@keyframes hatFloating {
  0%   { transform: translateY(0px); }
  50%  { transform: translateY(-3px); }
  100% { transform: translateY(0px); }
}
.msg-avatar-me-container::after,
.msg-avatar-them-container::after {
  animation: hatFloating 3s ease-in-out infinite !important;
}
.msg-avatar-them-container::after {
  animation-delay: 0.5s !important;
}

/* 气泡 Q 弹入场动画 */
@keyframes qBounceMe {
  0% { opacity: 0; transform: scale(0.4) translateY(15px); }
  100% { opacity: 1; transform: scale(1) translateY(0px); }
}
@keyframes qBounceThem {
  0% { opacity: 0; transform: scale(0.4) translateY(15px); }
  100% { opacity: 1; transform: scale(1) translateY(0px); }
}
.msg-me {
  transform-origin: bottom right !important;
  animation: qBounceMe 0.45s cubic-bezier(0.34, 1.56, 0.64, 1) forwards !important;
}
.msg-them {
  transform-origin: bottom left !important;
  animation: qBounceThem 0.45s cubic-bezier(0.34, 1.56, 0.64, 1) forwards !important;
}

