    text-align: center !important;
    color: #ffffff !important;
    font-size: 15px !important; 
    margin-top: -40px !important; 
}


/* =========================================
   2. 昵称下方的状态栏贴图装饰（已彻底清空外框与默认文字）
========================================= */

.call-status { 
    font-size: 0 !important; 
    color: transparent !important;

    /* 🔴 彻底清除系统默认的半透明背景底色、圆角、边框和阴影 */
    background: transparent !important; 
    background-color: transparent !important;
    border: none !important;
    box-shadow: none !important;
    border-radius: 0 !important;
    padding: 0 !important;
}

/* 🔴 强制隐藏外框里原本带有的“声：背景声音”文字及自带小图标 */
.call-status * {
    display: none !important;
}

/* 注入你的装饰贴图 */
.call-status::before {
    content: "" !important;
    display: block !important;
    background-image: url("https://img.cdn1.vip/i/6a45c74c70c58_1782957900.png") !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    background-size: contain !important;
    width: 100px !important;
    height: 35px !important;
    margin: -6px auto 0 auto !important;

    /* 🌟 调整昵称下方装饰的大小 🌟 */
    transform: scale(1.0) !important; 
}


/* =========================================
   3. 底部三个功能按钮 
========================================= */

.control-btn svg { display: none !important; }

/* 基础底框：只对上方三个按钮生效 */
.control-btn:not(.end-call-btn):not(.vc-btn-end) {
    background-color: transparent !important; 
    border: none !important;
    box-shadow: none !important;
    background-position: center !important;
    background-repeat: no-repeat !important;
    width: 75px !important;
    height: 75px !important;

    /* 🌟 统一调整上面三个功能键贴图的大小 🌟 */
    transform: scale(0.7) !important; 
}

